// Identifica grupo pelo JID (formato: xxxxx@g.us) e extrai mensagem.
// FIX B2: antes usava body.data.pushName, que e o nome do remetente, nao do grupo.
// Agora usa key.remoteJid (JID do grupo) + tabela MAPA_GRUPOS.

const body = $input.first().json;

// TODO Luiz: preencher os JIDs reais de cada grupo.
// Como obter: GET {{EVOLUTION_API_URL}}/group/fetchAllGroups/{{EVOLUTION_INSTANCE}}
// Cada grupo tem campo 'id' com o formato 120363xxxxxxx@g.us
const MAPA_GRUPOS = {
  'TODO_K2CON@g.us':       { nome: 'K2Con',      projeto: 'k2con' },
  'TODO_EG_FOOD@g.us':     { nome: 'EG Food',    projeto: 'eg_food' },
  'TODO_GESTAO_EG@g.us':   { nome: 'Gestao EG',  projeto: 'gestao_eg' },
  'TODO_MKT_EG@g.us':      { nome: 'MKT EG',     projeto: 'mkt_eg' },
  'TODO_QUICKBOOKS@g.us':  { nome: 'Quickbooks', projeto: 'quickbooks' },
  'TODO_EG_GERAL@g.us':    { nome: 'EG Geral',   projeto: 'geral' }
};

const remoteJid = body.data?.key?.remoteJid || '';
const isGrupo = remoteJid.endsWith('@g.us');
const info = MAPA_GRUPOS[remoteJid] || { nome: 'EG Geral', projeto: 'geral' };

const tipoMensagem = body.data?.message?.audioMessage ? 'audio' : 'texto';
const mensagemTexto = body.data?.message?.conversation
  || body.data?.message?.extendedTextMessage?.text
  || '';
const audioUrl = body.data?.message?.audioMessage
  ? (body.data?.message?.audioMessage?.url || body.data?.url)
  : null;

return [{
  json: {
    grupo: info.nome,
    projeto: info.projeto,
    remote_jid: remoteJid,
    is_grupo: isGrupo,
    tipo_mensagem: tipoMensagem,
    mensagem_texto: mensagemTexto,
    audio_url: audioUrl,
    remetente: remoteJid,
    participante: body.data?.key?.participant || '',
    push_name_remetente: body.data?.pushName || '',
    timestamp: new Date().toISOString()
  }
}];
